    def fetch_markets(self, params={}) -> List[Market]:
        aggregated = []
        offset = 0
        pageLimit = 100
        paging = True
        while(paging):
            q = self.extend({'limit': pageLimit, 'offset': offset}, params)
            response = self.request('futures', 'private', 'GET', q)
            data = self.safe_value(response, 'data', [])
            items = []
            if isinstance(data, dict) and not isinstance(data, list):
                items = self.safe_list(data, 'items', [])
                if not len(items):
                    items = self.safe_list(data, 'results', [])
                if not len(items) and ('symbol' in data):
                    items = [data]
            else:
                items = self.to_array(data)
            if not len(items):
                paging = False
                break
            for i in range(0, len(items)):
                aggregated.append(items[i])
            if len(items) < pageLimit:
                paging = False
            else:
                offset += pageLimit
        result = []
        for i in range(0, len(aggregated)):
            result.append(self.parse_market(aggregated[i]))
        return result

