    def fetch_balance(self, params={}) -> Balances:
        self.load_markets()
        tradeCurrency = self.safe_string_2(params, 'trade_currency', 'tradeCurrency')
        spotReq: dict = {}
        futReq: dict = {}
        if tradeCurrency is not None:
            spotReq['currency'] = tradeCurrency
            futReq['trade_currency'] = tradeCurrency
        elif params['currency'] is not None:
            spotReq['currency'] = params['currency']
            futReq['trade_currency'] = params['currency']
        p1 = self.omit(params, ['trade_currency', 'tradeCurrency', 'currency'])
        spot = self.request('wallet/funds', 'private', 'GET', self.extend(spotReq, p1))
        fut = self.request('futures/funds', 'private', 'GET', self.extend(futReq, p1))
        return self.parse_balance({'spot': spot, 'futures': fut, 'currency': spotReq['currency'] or 'USDT'})

    def parse_balance(self, response: Any) -> Balances:
        spotR = self.safe_dict(response, 'spot', {})
        futR = self.safe_dict(response, 'futures', {})
        spotD = self.safe_dict(spotR, 'data', {})
        futD = self.safe_dict(futR, 'data', {})
        currency = self.safe_string(response, 'currency', 'USDT')
        futBal = self.safe_number(futD, 'balance')
        futLocked = self.safe_number(futD, 'locked_amount')
        futFree = None
        if futBal is not None and futLocked is not None:
            futFree = futBal - futLocked
        spotWithdrawable = self.safe_number(spotD, 'withdrawable')
        timestamp = self.milliseconds()
        balance: dict = {
            'info': [spotR, futR],
            'timestamp': timestamp,
            'datetime': self.iso8601(timestamp),
        }
        balance[currency] = {
            'free': futFree,
            'used': futLocked,
            'total': futBal,
        }
        if spotWithdrawable is not None:
            balance['SPOT'] = {
                'free': spotWithdrawable,
                'used': 0,
                'total': self.safe_number(spotD, 'total'),
            }
        return self.safe_balance(balance)

