    def set_leverage(self, leverage: Int, symbol: Str = None, params={}) -> Any:
        if symbol is None:
            raise ArgumentsRequired(self.id + ' setLeverage() requires a symbol')
        self.load_markets()
        market = self.market(symbol)
        marginType = self.safe_string(params, 'marginType', 'ISOLATED')
        body: dict = {
            'margin_type': marginType,
            'leverage': leverage,
        }
        tradeCurrency = self.safe_string_2(params, 'trade_currency', 'tradeCurrency')
        if tradeCurrency is not None:
            body['trade_currency'] = tradeCurrency
        path = 'futures/' + market['id'] + '/leverage?is_symbol=1'
        response = self.request(path, 'private', 'POST', self.extend(body, self.omit(params, ['trade_currency', 'tradeCurrency', 'marginType'])))
        leverages = self.safe_dict(self.options, 'leverages', {})
        self.options['leverages'] = self.extend(leverages, {[market['symbol']]: leverage})
        return response

    def create_order(self, symbol: str, type: OrderType, side: OrderSide, amount: float, price: Num = None, params={}) -> Order:
        self.check_required_credentials()
        self.load_markets()
        market = self.market(symbol)
        ms = market['id']
        lev = self.safe_integer(params, 'leverage')
        leverages = self.safe_dict(self.options, 'leverages', {})
        if lev is None:
            lev = self.safe_integer(leverages, market['symbol'])
        if lev is None:
            raise ArgumentsRequired(self.id + " createOrder() requires params['leverage'] or a prior setLeverage() call")
        trig = 'MARKET' if (type == 'market') else 'LIMIT'
        otype = 'LONG' if (side == 'buy') else 'SHORT'
        px = price
        if type == 'market' and (px is None or px == 0):
            t = self.fetch_ticker(symbol)
            px = self.safe_number(t, 'last')
            if px is None:
                raise ExchangeError(self.id + ' could not resolve market order price from ticker')
        body: dict = {
            'leverage': str(lev),
            'quantity': str(amount),
            'order_price': str(px),
            'order_type': otype,
            'trigger_type': trig,
            'reduce_only': self.safe_bool(params, 'reduceOnly', False),
        }
        tradeCurrency = self.safe_string_2(params, 'trade_currency', 'tradeCurrency')
        if tradeCurrency is not None:
            body['trade_currency'] = tradeCurrency
        if self.safe_bool(params, 'takeProfit', False) or params['takeprofit_price'] is not None:
            body['is_takeprofit'] = True
            tp = self.safe_string_2(params, 'takeprofit_price', 'takeProfitPrice')
            if tp is not None:
                body['takeprofit_price'] = tp
        if self.safe_bool(params, 'stopLoss', False) or params['stoploss_price'] is not None:
            body['is_stoploss'] = True
            sl = self.safe_string_2(params, 'stoploss_price', 'stopLossPrice')
            if sl is not None:
                body['stoploss_price'] = sl
        path = 'futures/' + ms + '/order?is_symbol=1'
        response = self.request(path, 'private', 'POST', self.extend(body, self.omit(params, ['leverage', 'reduceOnly', 'takeProfit', 'stopLoss', 'takeprofit_price', 'takeProfitPrice', 'stoploss_price', 'stopLossPrice', 'trade_currency', 'tradeCurrency'])))
        leverages = self.safe_dict(self.options, 'leverages', {})
        self.options['leverages'] = self.extend(leverages, {[market['symbol']]: lev})
        data = self.safe_dict(response, 'data', response)
        return self.parse_order(data, market)

